const results = [];

for (const item of $input.all()) {
  if (item.json.billable === true) {
    results.push({ json: item.json });
  }
}

return results;

const totali = {};

for (const item of $input.all()) {
  const projectId = item.json.project?.id ?? item.json.project ?? null;
  const duration = Number(item.json.duration ?? 0);

  if (!projectId) continue;

  if (!totali[projectId]) {
    totali[projectId] = 0;
  }

  totali[projectId] += duration;
}

const results = Object.entries(totali)
  .map(([id, totalSeconds]) => ({
    json: {
      id: Number(id),
      total_seconds: totalSeconds,
      total_ore: Math.round((totalSeconds / 3600) * 100) / 100
    }
  }))
  .sort((a, b) => a.json.id - b.json.id);

return results;

const daysThreshold = 10;

const now = new Date();
const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());

const msPerDay = 1000 * 60 * 60 * 24;
const projects = [];

function formatIsoToItalian(isoDate) {
  if (!isoDate) return null;

  const parts = String(isoDate).split("-");
  if (parts.length !== 3) return null;

  return `${parts[2]}/${parts[1]}/${parts[0]}`;
}

function getDaysDiff(date) {
  if (!date) return null;
  return Math.round((date.getTime() - today.getTime()) / msPerDay);
}

function getUrgency(days) {
  if (days === null || days === undefined) return "none";
  if (days < 0) return "expired";
  if (days <= 3) return "high";
  if (days <= 7) return "medium";
  return "low";
}

function getStatus(days) {
  if (days === null || days === undefined) return "not_present";
  return days < 0 ? "expired" : "expiring";
}

function getBudgetInfo(timeBudget, totalSeconds) {
  if (!timeBudget || timeBudget <= 0) return null;

  const percentage = Math.round((totalSeconds / timeBudget) * 100);
  const usedHours = Math.round((totalSeconds / 3600) * 100) / 100;
  const budgetHours = Math.round((timeBudget / 3600) * 100) / 100;
  const remainingHours = Math.round(((timeBudget - totalSeconds) / 3600) * 100) / 100;

  return {
    percentage,
    usedHours,
    budgetHours,
    remainingHours,
    exceeded: percentage >= 100,
    shouldReport: percentage >= 80
  };
}

for (const item of $input.all()) {
  const id = item.json.id ?? null;
  const name = String(item.json.name ?? "");
  const customer = String(item.json.parentTitle ?? "");

  const endRaw = item.json.end ?? null;

  let projectDeadline = "not present";
  let projectDeadlineIso = null;
  let projectDays = null;
  let projectUrgency = "none";
  let projectStatus = "not_present";

  if (endRaw) {
    const endDate = new Date(`${endRaw}T00:00:00`);
    if (!isNaN(endDate.getTime())) {
      projectDeadline = formatIsoToItalian(endRaw) || endRaw;
      projectDeadlineIso = endRaw;
      projectDays = getDaysDiff(endDate);
      projectUrgency = getUrgency(projectDays);
      projectStatus = getStatus(projectDays);
    }
  }

  const timeBudget = Number(item.json.timeBudget ?? 0);
  const totalSeconds = Number(item.json.total_seconds ?? 0);
  const budget = getBudgetInfo(timeBudget, totalSeconds);

  const projectShouldReport =
    projectDays !== null && projectDays >= 0 && projectDays <= daysThreshold;

  const budgetShouldReport =
    budget !== null && budget.shouldReport;

  const shouldReport =
    projectShouldReport ||
    budgetShouldReport;

  if (!shouldReport) {
    continue;
  }

  projects.push({
    id,
    name,
    customer,

    project_deadline: projectDeadline,
    project_deadline_iso: projectDeadlineIso,
    project_days: projectDays,
    project_urgency: projectUrgency,
    project_status: projectStatus,

    budget_set: timeBudget > 0,
    budget_total_hours: budget ? budget.budgetHours : null,
    budget_used_hours: budget ? budget.usedHours : null,
    budget_remaining_hours: budget ? budget.remainingHours : null,
    budget_percentage: budget ? budget.percentage : null,
    budget_exceeded: budget ? budget.exceeded : false,
    budget_should_report: budget ? budget.shouldReport : false
  });
}

projects.sort((a, b) => {
  const aVal = a.project_days ?? 999999;
  const bVal = b.project_days ?? 999999;
  return aVal - bVal;
});

return [
  {
    json: {
      daysThreshold,
      count: projects.length,
      projects
    }
  }
];

const projects = $json.projects || [];
const todayDate = $now.setLocale('en').toFormat('dd LLL yyyy');
const count = Number($json.count || 0);
const daysThreshold = Number($json.daysThreshold || 10);

const urgencyConfig = {
  expired: { color: '#ef4444', background: '#fef2f2', icon: '🚨', label: 'EXPIRED', action: 'TAKE ACTION' },
  high:    { color: '#f97316', background: '#fff7ed', icon: '🔥', label: 'URGENT', action: 'DUE SOON' },
  medium:  { color: '#d97706', background: '#fffbeb', icon: '⏳', label: 'WARNING', action: 'TO MONITOR' },
  low:     { color: '#10b981', background: '#ecfdf5', icon: '✅', label: 'OK', action: 'ON TRACK' },
  none:    { color: '#6366f1', background: '#f5f3ff', icon: '🔍', label: 'TO CHECK', action: 'MISSING DATA' }
};

const escapeHtml = (v) =>
  String(v ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');

const buildStatusBlock = (urgency, date, label) => {
  const cfg = urgencyConfig[urgency] || urgencyConfig.none;
  const isMissing = !date || date === 'not present';

  return `
    <div style="background: ${cfg.background}; border-radius: 16px; padding: 14px; border: 1px solid ${cfg.color}${isMissing ? '60' : '20'}; min-height: 80px;">
      <div style="display: flex; align-items: center; margin-bottom: 6px;">
        <span style="font-size: 14px; margin-right: 6px;">${cfg.icon}</span>
        <span style="font-size: 10px; font-weight: 800; color: ${cfg.color}; text-transform: uppercase; letter-spacing: 1px;">${cfg.label}</span>
      </div>
      <div style="font-size: 15px; font-weight: 800; color: ${isMissing ? cfg.color : '#1e293b'}; margin-bottom: 2px;">
        ${escapeHtml(isMissing ? 'MISSING DATA' : date)}
      </div>
      <div style="font-size: 11px; color: #64748b; font-weight: 500;">${escapeHtml(label)}</div>
    </div>
  `;
};

const buildBudgetBlock = (p) => {
  if (!p.budget_set) {
    return `
      <div style="background: #f5f3ff; border-radius: 16px; padding: 16px; border: 1px dashed #6366f1; text-align: center;">
        <div style="font-size: 14px; margin-bottom: 4px;">🔍</div>
        <div style="font-size: 11px; font-weight: 800; color: #6366f1; text-transform: uppercase;">Budget not configured</div>
        <div style="font-size: 10px; color: #64748b; margin-top: 2px;">Check whether this project should be billable</div>
      </div>`;
  }

  const percent = Math.min(Number(p.budget_percentage ?? 0), 100);
  const isOver = p.budget_exceeded;
  const color = isOver ? '#ef4444' : (percent > 85 ? '#f97316' : '#3b82f6');

  return `
    <div style="background: #ffffff; border-radius: 16px; padding: 16px; border: 1px solid #e2e8f0;">
      <table width="100%" cellpadding="0" cellspacing="0">
        <tr>
          <td style="font-size: 12px; font-weight: 700; color: #1e293b;">Budget Usage</td>
          <td align="right" style="font-size: 12px; font-weight: 800; color: ${color};">${p.budget_percentage}%</td>
        </tr>
      </table>
      <div style="width: 100%; height: 8px; background: #f1f5f9; border-radius: 10px; margin: 10px 0; overflow: hidden;">
        <div style="width: ${percent}%; height: 100%; background: ${color}; border-radius: 10px;"></div>
      </div>
      <table width="100%" cellpadding="0" cellspacing="0">
        <tr>
          <td style="font-size: 11px; color: #64748b;"><strong>${p.budget_used_hours}h</strong> logged</td>
          <td align="right" style="font-size: 11px; color: #64748b;">Total: <strong>${p.budget_total_hours}h</strong></td>
        </tr>
      </table>
    </div>`;
};

const rowsHTML = projects.map((p) => {
  const projectLabel =
    p.project_status === 'not_present'
      ? 'Add the PO deadline'
      : (p.project_days < 0
          ? `Expired ${Math.abs(p.project_days)} days ago`
          : `In ${p.project_days} days`);

  return `
    <div style="margin-bottom: 30px; background: #ffffff; border-radius: 24px; box-shadow: 0 10px 25px rgba(0,0,0,0.05); border: 1px solid #e2e8f0; overflow: hidden;">
      <div style="padding: 20px; background: linear-gradient(to right, #f8fafc, #ffffff); border-bottom: 1px solid #f1f5f9;">
        <div style="font-size: 10px; font-weight: 800; color: #3b82f6; text-transform: uppercase; letter-spacing: 1.5px; margin-bottom: 4px;">${escapeHtml(p.customer)}</div>
        <div style="font-size: 20px; font-weight: 900; color: #0f172a; letter-spacing: -0.5px;">${escapeHtml(p.name)}</div>
      </div>

      <div style="padding: 20px;">
        <div style="font-size: 10px; font-weight: 700; color: #94a3b8; text-transform: uppercase; margin-bottom: 8px;">Order Deadline (PO)</div>
        ${buildStatusBlock(p.project_urgency, p.project_deadline, projectLabel)}

        <div style="height: 16px;"></div>

        <div style="font-size: 10px; font-weight: 700; color: #94a3b8; text-transform: uppercase; margin-bottom: 8px;">Hours Monitoring</div>
        ${buildBudgetBlock(p)}
      </div>
    </div>`;
}).join('');

const html = `<!DOCTYPE html>
<html lang="en">
<body style="margin:0; padding:0; background-color:#f8fafc; font-family:'Inter', -apple-system, system-ui, sans-serif;">
  <table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #f8fafc; padding: 40px 10px;">
    <tr>
      <td align="center">
        <table width="600" cellpadding="0" cellspacing="0" border="0" style="width: 100%; max-width: 600px;">
          <tr>
            <td style="padding-bottom: 30px; text-align: center;">
              <div style="font-size: 12px; font-weight: 800; color: #3b82f6; text-transform: uppercase; letter-spacing: 2px; margin-bottom: 8px;">Timesheet Analysis</div>
              <h1 style="font-size: 36px; font-weight: 900; color: #0f172a; margin: 0; letter-spacing: -1.5px;">Deadline Report</h1>
              <p style="font-size: 16px; color: #64748b; margin-top: 10px;">Detected <strong>${count} projects</strong> to manage or verify.</p>
            </td>
          </tr>

          <tr>
            <td>${rowsHTML}</td>
          </tr>

          <tr>
            <td style="padding-top: 20px; text-align: center;">
              <a href="https://kimai.com" style="display: inline-block; background: #0f172a; color: #ffffff; padding: 16px 40px; border-radius: 18px; text-decoration: none; font-weight: 700; font-size: 15px; box-shadow: 0 10px 20px rgba(15,23,42,0.1);">Open Timesheet &rarr;</a>
              <div style="margin-top: 40px; border-top: 1px solid #e2e8f0; padding-top: 20px; font-size: 12px; color: #94a3b8; letter-spacing: 0.5px;">
                Automatically generated on ${todayDate}
              </div>
            </td>
          </tr>
        </table>
      </td>
    </tr>
  </table>
</body>
</html>`;

return [
  {
    json: {
      html,
      subject: `[Timesheet] - Projects Deadline Report`
    }
  }
];
